pub fn count_color_frequencies(colors: &[&str]) -> Result<BTreeMap<String, usize>, String> {
    if colors.len() > 2500 {
        return Err("Input exceeds maximum allowed size of 2500 elements".to_string());
    }
    let mut color_counts = BTreeMap::new();
    for &color in colors {
        let normalized = color.to_lowercase();
        *color_counts.entry(normalized).or_insert(0) += 1;
    }
    Ok(color_counts)
