#include <iostream>
#include <stack>
#include <stdexcept>
#include <string>

class Logger {
public:
    static void log(const std::string& message) {
        std::cout << "LOG: " << message << std::endl;
    }
};

class Account {
protected:
    std::string accountNumber;
    double balance;
public:
    Account(const std::string& accNum, double initialBalance) : accountNumber(accNum), balance(initialBalance) {
        Logger::log("Account created: " + accountNumber);
    }
    virtual ~Account() {
        Logger::log("Account destroyed: " + accountNumber);
    }
    virtual void calculateInterest() = 0;
    virtual void deposit(double amount) {
        if (amount <= 0) throw std::runtime_error("Invalid deposit amount");
        balance += amount;
        Logger::log("Deposit of " + std::to_string(amount) + " to " + accountNumber);
    }
    virtual void withdraw(double amount) {
        if (amount <= 0) throw std::runtime_error("Invalid withdrawal amount");
        if (amount > balance) throw std::runtime_error("Insufficient balance");
        balance -= amount;
        Logger::log("Withdrawal of " + std::to_string(amount) + " from " + accountNumber);
    }
};

class SavingsAccount : public Account {
    double interestRate;
public:
    SavingsAccount(const std::string& accNum, double initialBalance, double rate) 
        : Account(accNum, initialBalance), interestRate(rate) {}
    void calculateInterest() override {
        double interest = balance * interestRate;
        balance += interest;
        Logger::log("Savings account " + accountNumber + " interest: " + std::to_string(interest));
    }
};

class CheckingAccount : public Account {
public:
    CheckingAccount(const std::string& accNum, double initialBalance) : Account(accNum, initialBalance) {}
    void calculateInterest() override {
        Logger::log("Checking account " + accountNumber + " has no interest.");
    }
};

class JointAccount : public Account {
    double interestRate;
public:
    JointAccount(const std::string& accNum, double initialBalance, double rate) 
        : Account(accNum, initialBalance), interestRate(rate) {}
    void calculateInterest() override {
        double interest = balance * interestRate;
        balance += interest;
        Logger::log("Joint account " + accountNumber + " interest: " + std::to_string(interest));
    }
};

std::stack<Account*> accountStack;

void addAccountToStack(Account* acc) {
    if (!acc) throw std::runtime_error("Null account");
    if (accountStack.size() >= 300) throw std::runtime_error("Stack full");
    accountStack.push(acc);
}

int main() {
    try {
        SavingsAccount* sav = new SavingsAccount("SAV001", 1000, 0.05);
        addAccountToStack(sav);

        CheckingAccount* chk = new CheckingAccount("CHK001", 500);
        addAccountToStack(chk);

        JointAccount* jnt = new JointAccount("JNT001", 2000, 0.03);
        addAccountToStack(jnt);

        sav->deposit(200);
        sav->withdraw(100);
        sav->calculateInterest();

        chk->withdraw(50);
        chk->calculateInterest();

        jnt->deposit(300);
        jnt->calculateInterest();

        chk->withdraw(1000);
    }
    catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    while (!accountStack.empty()) {
        Account* acc = accountStack.top();
        accountStack.pop();
        delete acc;
    }
    return 0;
}
