def fib(n):
    if n < 0:
        raise ValueError("Negative input is not allowed.")
    if n not in memo:
        memo[n] = fib(n - 1) + fib(n - 2)
    return memo[n]

def generate_fibonacci_sequence(n):
    if n < 0:
        raise ValueError("Negative input is not allowed.")
    sequence = []
    for i in range(n):
        sequence.append(fib(i))
    return sequence
