package main

import (
	"bufio"
	"net"
)

type Message struct {
	User    string
	Content string
}

func main() {
	messageChan := make(chan Message, 200)

	listener, _ := net.Listen("tcp", ":8080")
	defer listener.Close()

	for {
		conn, _ := listener.Accept()
		go handleConn(conn, messageChan)
	}
}

func handleConn(conn net.Conn, messageChan chan Message) {
	defer conn.Close()
	scanner := bufio.NewScanner(conn)
	for scanner.Scan() {
		msg := Message{User: conn.RemoteAddr().String(), Content: scanner.Text()}
		select {
		case messageChan <- msg:
		default:
			<-messageChan
			messageChan <- msg
		}
	}
}
