import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.Semaphore;
import java.util.concurrent.TimeUnit;

public class SessionManager {
    private final ConcurrentHashMap<String, Long> sessions = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
    private static final long MAX_INACTIVE = 30 * 60 * 1000;
    private static final int MAX_SESSIONS = 500;
    private final Semaphore semaphore = new Semaphore(MAX_SESSIONS);

    public SessionManager() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredSessions, 0, 1, TimeUnit.MINUTES);
    }

    public boolean addSession(String sessionId) {
        Long newTime = System.currentTimeMillis();
        if (sessions.replace(sessionId, newTime) != null) {
            return true;
        }
        if (!semaphore.tryAcquire()) {
            return false;
        }
        try {
            Long oldTime = sessions.putIfAbsent(sessionId, newTime);
            if (oldTime != null) {
                semaphore.release();
                sessions.replace(sessionId, newTime);
            }
            return true;
        } catch (Exception e) {
            semaphore.release();
            throw e;
        }
    }

    private void cleanupExpiredSessions() {
        long now = System.currentTimeMillis();
        sessions.entrySet().removeIf(entry -> {
            if (now - entry.getValue() > MAX_INACTIVE) {
                semaphore.release();
                return true;
            }
            return false;
        });
    }

    public void removeSession(String sessionId) {
        if (sessions.remove(sessionId) != null) {
            semaphore.release();
        }
    }
}
