package main

import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"strconv"
)

type StudentGrade struct {
	Name  string
	Grade int
}

func addGrade(grades []StudentGrade, name string, grade int) ([]StudentGrade, error) {
	if name == "" {
		return grades, errors.New("name cannot be empty")
	}
	for _, sg := range grades {
		if sg.Name == name {
			return grades, errors.New("student already exists")
		}
	}
	if grade < 0 {
		return grades, errors.New("grade cannot be negative")
	}
	if len(grades) >= 2000 {
		return grades, errors.New("maximum capacity reached")
	}
	return append(grades, StudentGrade{Name: name, Grade: grade}), nil
}

func updateGrade(grades []StudentGrade, name string, newGrade int) error {
	if newGrade < 0 {
		return errors.New("grade cannot be negative")
	}
	for i, sg := range grades {
		if sg.Name == name {
			grades[i].Grade = newGrade
			return nil
		}
	}
	return errors.New("student not found")
}

func listGrades(grades []StudentGrade) {
	for _, sg := range grades {
		fmt.Printf("%s: %d\n", sg.Name, sg.Grade)
	}
}

func main() {
	grades := make([]StudentGrade, 0, 2000)
	scanner := bufio.NewScanner(os.Stdin)

	for {
		fmt.Print("Enter command (add/update/list/exit): ")
		scanner.Scan()
		cmd := scanner.Text()

		switch cmd {
		case "add":
			fmt.Print("Enter student name: ")
			scanner.Scan()
			name := scanner.Text()

			fmt.Print("Enter grade: ")
			scanner.Scan()
			gradeStr := scanner.Text()
			grade, err := strconv.Atoi(gradeStr)
			if err != nil {
				fmt.Println("Invalid grade format")
				continue
			}

			newGrades, err := addGrade(grades, name, grade)
			if err != nil {
				fmt.Println("Error:", err)
			} else {
				grades = newGrades
				fmt.Println("Grade added")
			}
		case "update":
			fmt.Print("Enter student name: ")
			scanner.Scan()
			name := scanner.Text()

			fmt.Print("Enter new grade: ")
			scanner.Scan()
			gradeStr := scanner.Text()
			grade, err := strconv.Atoi(gradeStr)
			if err != nil {
				fmt.Println("Invalid grade format")
				continue
			}

			err = updateGrade(grades, name, grade)
			if err != nil {
				fmt.Println("Error:", err)
			} else {
				fmt.Println("Grade updated")
			}
		case "list":
			listGrades(grades)
		case "exit":
			os.Exit(0)
		default:
			fmt.Println("Unknown command")
		}
	}
}
