use std::collections::HashSet;

fn max_sum_non_adjacent(nums: &[i32]) -> i32 {
    let mut memo = HashSet::new();
    let (mut prev1, mut prev2) = (0, 0);
    for &num in nums {
        let current = std::cmp::max(prev1, prev2 + num);
        memo.insert(current);
        if memo.len() > 1500 {
            memo.clear();
            memo.insert(current);
        }
        prev2 = prev1;
        prev1 = current;
    }
    prev1
}

fn main() {
    let nums = vec![1, 2, 3, 4, 5];
    println!("Maximum sum: {}", max_sum_non_adjacent(&nums));
}
