class Flight {
private:
    std::string flightNumber;
    int capacity;
    int reservedSeats;

public:
    Flight(const std::string& num, int cap) : flightNumber(num), capacity(cap), reservedSeats(0) {}

    void reserveSeats(int seats) {
        if (reservedSeats + seats > capacity) {
            throw std::runtime_error("Not enough seats available");
        }
        reservedSeats += seats;
    }

    void cancelReservation(int seats) {
        if (reservedSeats - seats < 0) {
            throw std::runtime_error("Invalid cancellation");
        }
        reservedSeats -= seats;
    }

    int getAvailableSeats() const { return capacity - reservedSeats; }
    std::string getFlightNumber() const { return flightNumber; }
};

class Airline {
private:
    std::unordered_map<std::string, Flight> flights;

public:
    void addFlight(const std::string& num, int cap) {
        if (flights.size() >= 300) {
            throw std::runtime_error("Maximum flight limit reached");
        }
        flights.emplace(num, Flight(num, cap));
    }

    void reserveSeats(const std::string& num, int seats) {
        auto it = flights.find(num);
        if (it == flights.end()) {
            throw std::runtime_error("Flight not found");
        }
        it->second.reserveSeats(seats);
    }

    void cancelReservation(const std::string& num, int seats) {
        auto it = flights.find(num);
        if (it == flights.end()) {
            throw std::runtime_error("Flight not found");
        }
        it->second.cancelReservation(seats);
    }

    int checkAvailability(const std::string& num) {
        auto it = flights.find(num);
        if (it == flights.end()) {
            throw std::runtime_error("Flight not found");
        }
        return it->second.getAvailableSeats();
    }
};

class ReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;

public:
    void addAirline(const std::string& name) {
        airlines.emplace(name, Airline());
    }

    void addFlight(const std::string& airline, const std::string& num, int cap) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found");
        }
        it->second.addFlight(num, cap);
    }

    void reserveSeats(const std::string& airline, const std::string& num, int seats) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found");
        }
        it->second.reserveSeats(num, seats);
    }

    void cancelReservation(const std::string& airline, const std::string& num, int seats) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found");
        }
        it->second.cancelReservation(num, seats);
    }

    int checkAvailability(const std::string& airline, const std::string& num) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) {
            throw std::runtime_error("Airline not found");
        }
        return it->second.checkAvailability(num);
    }
};

int main() {
    ReservationSystem system;
    system.addAirline("Delta");
    system.addFlight("Delta", "DL101", 150);

    try {
        system.reserveSeats("Delta", "DL101", 3);
        std::cout << "Available seats: " << system.checkAvailability("Delta", "DL101") << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
