#include <iostream>
#include <queue>
#include <unordered_set>

using namespace std;

struct Node {
    int x, y;
};

int main() {
    int N, sx, sy, ex, ey;
    cin >> N >> sx >> sy >> ex >> ey;

    if (sx == ex && sy == ey) {
        cout << 0 << endl;
        return 0;
    }

    queue<pair<Node, int>> q;
    unordered_set<int> visited;
    auto hash = [](int x, int y) { return x * 1000 + y; };

    q.push({{sx, sy}, 0});
    visited.insert(hash(sx, sy));

    const int dx[] = {-1, 1, 0, 0};
    const int dy[] = {0, 0, -1, 1};

    while (!q.empty()) {
        auto [node, dist] = q.front();
        q.pop();

        for (int i = 0; i < 4; ++i) {
            int nx = node.x + dx[i], ny = node.y + dy[i];
            if (nx < 0 || nx >= N || ny < 0 || ny >= N) continue;
            if (nx == ex && ny == ey) {
                cout << dist + 1 << endl;
                return 0;
            }
            int key = hash(nx, ny);
            if (!visited.count(key)) {
                visited.insert(key);
                q.push({{nx, ny}, dist + 1});
            }
        }
    }

    cout << -1 << endl;
    return 0;
}
