import java.util.ArrayList;

public class FileCache {
    private ArrayList<FileMetadata> files = new ArrayList<>();

    public static class FileMetadata {
        private String filename;
        private long lastModified;
        private long fileSize;

        public FileMetadata(String filename, long lastModified, long fileSize) {
            this.filename = filename;
            this.lastModified = lastModified;
            this.fileSize = fileSize;
        }

        public String getFilename() { return filename; }
        public long getLastModified() { return lastModified; }
        public long getFileSize() { return fileSize; }
    }

    public void addFile(String filename, long lastModified, long fileSize) {
        for (int i = 0; i < files.size(); i++) {
            if (files.get(i).getFilename().equals(filename)) {
                files.remove(i);
                break;
            }
        }
        files.add(new FileMetadata(filename, lastModified, fileSize));
    }

    public FileMetadata getFileMetadata(String filename) {
        for (FileMetadata fm : files) {
            if (fm.getFilename().equals(filename)) return fm;
        }
        return null;
    }

    public boolean removeFile(String filename) {
        for (int i = 0; i < files.size(); i++) {
            if (files.get(i).getFilename().equals(filename)) {
                files.remove(i);
                return true;
            }
        }
        return false;
    }
}
