```go
package main

import (
	"errors"
	"fmt"
	"log"
	"math"
	"os"
	"sync"
)

var (
	infoLog  = log.New(os.Stdout, "INFO: ", log.Ldate|log.Ltime|log.Lshortfile)
	warnLog  = log.New(os.Stderr, "WARN: ", log.Ldate|log.Ltime|log.Lshortfile)
	errorLog = log.New(os.Stderr, "ERROR: ", log.Ldate|log.Ltime|log.Lshortfile)
)

type Buffer struct {
	data    []float64
	maxSize int
	mutex   sync.Mutex
}

func NewBuffer(maxSize int) *Buffer {
	return &Buffer{
		maxSize: maxSize,
	}
}

func (b *Buffer) Add(temp float64) {
	b.mutex.Lock()
	defer b.mutex.Unlock()
	b.data = append(b.data, temp)
	if len(b.data) > b.maxSize {
		b.data = b.data[1:]
	}
}

func (b *Buffer) Average() (float64, error) {
	b.mutex.Lock()
	defer b.mutex.Unlock()
	if len(b.data) == 0 {
		return 0, errors.New("buffer is empty")
	}
	sum := 0.0
	for _, temp := range b.data {
		sum += temp
	}
	if math.IsInf(sum, 0) {
		return 0, errors.New("sum overflow")
	}
	return sum / float64(len(b.data)), nil
}

type SensorManager struct {
	sensors map[string]*Buffer
	mutex   sync.Mutex
}

func NewSensorManager() *SensorManager {
	return &SensorManager{
		sensors: make(map[string]*Buffer),
	}
}

func (sm *SensorManager) AddData(sensorID string, temp float64) {
	sm.mutex.Lock()
	defer sm.mutex.Unlock()
	if _, ok := sm.sensors[sensorID]; !ok {
		sm.sensors[sensorID] = NewBuffer(1000)
		infoLog.Printf("Created buffer for sensor %s", sensorID)
	}
	sm.sensors[sensorID].Add(temp)
	infoLog.Printf("Added %.2f to %s", temp, sensorID)
}

func (sm *SensorManager) GetAverage(sensorID string) (float64, error) {
	sm.mutex.Lock()
	defer sm.mutex.Unlock()
	buf, ok := sm.sensors[sensorID]
	if !ok {
		return 0, fmt.Errorf("sensor %s not found", sensorID)
	}
	avg, err := buf.Average()
	if err != nil {
		switch err.Error() {
		case "buffer is empty":
			warnLog.Printf("Buffer empty for %s", sensorID)
		case "sum overflow":
			errorLog.Printf("Sum overflow for %s", sensorID)
		}
		return 0, err
	}
	infoLog.Printf("Average for %s: %.2f", sensorID, avg)
	return avg, nil
}

func main() {
	sm := NewSensorManager()
	sm.AddData("sensor1", 20.5)
	avg, _ := sm.GetAverage("sensor1")
	fmt.Printf("Current average: %.2f\n", avg)
}
