package main

import (
	"math/big"
	"sync"
)

var (
	cache sync.Map
	mu    sync.Mutex
)

func fibonacci(n int) *big.Int {
	if n <= 1 {
		return big.NewInt(int64(n))
	}

	if val, ok := cache.Load(n); ok {
		return val.(*big.Int)
	}

	mu.Lock()
	defer mu.Unlock()

	if val, ok := cache.Load(n); ok {
		return val.(*big.Int)
	}

	highest := 0
	if hVal, ok := cache.Load("highest"); ok {
		highest = hVal.(int)
	} else {
		cache.Store(0, big.NewInt(0))
		cache.Store(1, big.NewInt(1))
		cache.Store("highest", 1)
		highest = 1
	}

	if n <= highest {
		val, _ := cache.Load(n)
		return val.(*big.Int)
	}

	a, _ := cache.Load(highest - 1)
	b, _ := cache.Load(highest)
	fibA := a.(*big.Int)
	fibB := b.(*big.Int)

	for i := highest + 1; i <= n; i++ {
		fibA, fibB = fibB, new(big.Int).Add(fibA, fibB)
		cache.Store(i, fibB)
	}

	cache.Store("highest", n)
	return fibB
}
