using namespace std;

struct Node {
    int val;
    int arrayIdx;
    int elementIdx;
    Node(int v, int a, int e) : val(v), arrayIdx(a), elementIdx(e) {}
};

struct Compare {
    bool operator()(const Node& a, const Node& b) {
        return a.val > b.val;
    }
};

vector<int> mergeSortedArrays(const vector<vector<int>>& arrays) {
    vector<int> result;
    priority_queue<Node, vector<Node>, Compare> pq;

    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            pq.emplace(arrays[i][0], i, 0);
        }
    }

    while (!pq.empty()) {
        Node current = pq.top();
        pq.pop();
        result.push_back(current.val);
        int nextIdx = current.elementIdx + 1;
        if (nextIdx < arrays[current.arrayIdx].size()) {
            pq.emplace(arrays[current.arrayIdx][nextIdx], current.arrayIdx, nextIdx);
        }
    }

    return result;
}
