import java.util.Queue;
import java.util.PriorityQueue;

public class TaskProcessor {
    public static class Task {
        private final int priority;
        private final long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }

        public int getPriority() {
            return priority;
        }

        public long getDuration() {
            return duration;
        }
    }

    public static long processTasks(Queue<Task> tasks) throws InterruptedException, IllegalArgumentException {
        if (tasks.isEmpty()) {
            throw new IllegalArgumentException("Queue is empty");
        }
        if (tasks.size() > 100) {
            throw new IllegalArgumentException("Maximum task limit exceeded");
        }

        PriorityQueue<Task> pq = new PriorityQueue<>((a, b) -> Integer.compare(b.getPriority(), a.getPriority()));
        pq.addAll(tasks);

        long startTime = System.currentTimeMillis();
        while (!pq.isEmpty()) {
            Thread.sleep(pq.poll().getDuration());
        }
        return System.currentTimeMillis() - startTime;
    }
}
