        if (products.size() >= 500) return false;
        products[p.id] = p;
        return true;
    }

    std::vector<Product> sortByPrice() {
        std::vector<Product> sorted;
        for (const auto& pair : products) sorted.push_back(pair.second);
        for (size_t i = 0; i < sorted.size(); ++i)
            for (size_t j = 0; j < sorted.size() - i - 1; ++j)
                if (sorted[j].price > sorted[j+1].price)
                    std::swap(sorted[j], sorted[j+1]);
        return sorted;
    }

    std::vector<Product> sortByGenre() {
        std::vector<Product> sorted;
        for (const auto& pair : products) sorted.push_back(pair.second);
        for (size_t i = 0; i < sorted.size(); ++i)
            for (size_t j = 0; j < sorted.size() - i - 1; ++j)
                if (sorted[j].genre > sorted[j+1].genre)
                    std::swap(sorted[j], sorted[j+1]);
        return sorted;
    }
