#include <iostream>
#include <fstream>
#include <vector>
#include <queue>
#include <sstream>
#include <string>

using namespace std;

struct HeapNode {
    int value;
    int arrayIdx;
    int elementIdx;
};

struct Compare {
    bool operator()(const HeapNode& a, const HeapNode& b) {
        return a.value > b.value;
    }
};

vector<int> parseArray(const string& str) {
    vector<int> arr;
    stringstream ss(str);
    string token;
    while (getline(ss, token, ',')) {
        arr.push_back(stoi(token));
    }
    return arr;
}

vector<int> mergeArrays(const vector<vector<int>>& arrays) {
    vector<int> result;
    priority_queue<HeapNode, vector<HeapNode>, Compare> min_heap;

    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            min_heap.push({arrays[i][0], i, 0});
        }
    }

    while (!min_heap.empty()) {
        HeapNode node = min_heap.top();
        min_heap.pop();
        result.push_back(node.value);
        if (node.elementIdx + 1 < arrays[node.arrayIdx].size()) {
            int nextIdx = node.elementIdx + 1;
            min_heap.push({arrays[node.arrayIdx][nextIdx], node.arrayIdx, nextIdx});
        }
    }

    return result;
}

int main(int argc, char* argv[]) {
    string inputFile, outputFile;
    vector<vector<int>> arrays;

    int i;
    for (i = 1; i < argc; ++i) {
        string arg = argv[i];
        if (arg == "-i" && i + 1 < argc) {
            inputFile = argv[++i];
        } else if (arg == "-o" && i + 1 < argc) {
            outputFile = argv[++i];
        } else {
            break;
        }
    }

    if (!inputFile.empty()) {
        ifstream in(inputFile);
        if (!in) {
            cerr << "Error opening input file." << endl;
            return 1;
        }
        string line;
        while (getline(in, line)) {
            arrays.push_back(parseArray(line));
        }
    } else {
        for (; i < argc; ++i) {
            arrays.push_back(parseArray(argv[i]));
        }
    }

    if (arrays.size() > 10) {
        cerr << "Error: Too many arrays (max 10)." << endl;
        return 1;
    }

    for (const auto& arr : arrays) {
        if (arr.size() > 200) {
            cerr << "Error: Array exceeds 200 elements." << endl;
            return 1;
        }
    }

    vector<int> merged = mergeArrays(arrays);

    if (!outputFile.empty()) {
        ofstream out(outputFile);
        if (!out) {
            cerr << "Error opening output file." << endl;
            return 1;
        }
        for (int num : merged) {
            out << num << " ";
        }
        out << endl;
    } else {
        for (int num : merged) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}
