use std::collections::HashMap;
use std::env;
use std::error::Error;
use std::fs;

fn process_word(word: &str) -> String {
    let word_lower = word.to_lowercase();
    let trimmed_start = word_lower.trim_start_matches(|c: char| !c.is_alphabetic() && c != '\'');
    let trimmed = trimmed_start.trim_end_matches(|c: char| !c.is_alphabetic() && c != '\'');
    trimmed.to_string()
}

fn main() -> Result<(), Box<dyn Error>> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <filename> [--top <N>]", args[0]);
        return Ok(());
    }

    let filename = &args[1];
    let content = fs::read_to_string(filename)?;

    let mut word_counts = HashMap::new();

    for word in content.split_whitespace() {
        let processed = process_word(word);
        if processed.is_empty() {
            continue;
        }

        match word_counts.entry(processed) {
            std::collections::hash_map::Entry::Occupied(mut e) => *e.get_mut() += 1,
            std::collections::hash_map::Entry::Vacant(e) => {
                if word_counts.len() < 10_000 {
                    e.insert(1);
                }
            }
        }
    }

    if args.len() >= 4 && args[2] == "--top" {
        if let Ok(n) = args[3].parse::<usize>() {
            let mut counts: Vec<_> = word_counts.into_iter().collect();
            counts.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));

            for (i, (word, count)) in counts.iter().take(n).enumerate() {
                println!("{}. {}: {}", i + 1, word, count);
            }
        }
    }

    Ok(())
}
