use std::collections::LinkedList;
use std::time::SystemTime;
use std::fmt;

#[derive(Debug)]
pub struct Message {
    pub id: u32,
    pub timestamp: SystemTime,
    pub content: String,
}

pub struct MessageQueue {
    messages: LinkedList<Message>,
    max_capacity: usize,
}

#[derive(Debug, PartialEq)]
pub enum QueueError {
    Overflow,
    Underflow,
    NotFound,
}

impl fmt::Display for QueueError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            QueueError::Overflow => write!(f, "Queue overflow"),
            QueueError::Underflow => write!(f, "Queue underflow"),
            QueueError::NotFound => write!(f, "Message not found"),
        }
    }
}

impl std::error::Error for QueueError {}

impl MessageQueue {
    pub fn new(max_capacity: usize) -> Self {
        MessageQueue {
            messages: LinkedList::new(),
            max_capacity,
        }
    }

    pub fn enqueue(&mut self, message: Message) -> Result<(), QueueError> {
        if self.messages.len() >= self.max_capacity {
            return Err(QueueError::Overflow);
        }
        self.messages.push_back(message);
        Ok(())
    }

    pub fn dequeue(&mut self) -> Result<Message, QueueError> {
        self.messages.pop_front().ok_or(QueueError::Underflow)
    }

    pub fn find_by_id(&self, id: u32) -> Result<&Message, QueueError> {
        self.messages
            .iter()
            .find(|m| m.id == id)
            .ok_or(QueueError::NotFound)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn sample_message(id: u32) -> Message {
        Message {
            id,
            timestamp: SystemTime::now(),
            content: String::new(),
        }
    }

    #[test]
    fn enqueue_within_capacity() {
        let mut q = MessageQueue::new(2);
        assert!(q.enqueue(sample_message(1)).is_ok());
        assert!(q.enqueue(sample_message(2)).is_ok());
        assert_eq!(q.enqueue(sample_message(3)).err(), Some(QueueError::Overflow));
    }

    #[test]
    fn dequeue_from_empty() {
        let mut q = MessageQueue::new(1);
        assert_eq!(q.dequeue().err(), Some(QueueError::Underflow));
    }

    #[test]
    fn find_existing_message() {
        let mut q = MessageQueue::new(1);
        q.enqueue(sample_message(42)).unwrap();
        assert!(q.find_by_id(42).is_ok());
    }

    #[test]
    fn find_nonexistent_message() {
        let q = MessageQueue::new(1);
        assert_eq!(q.find_by_id(99).err(), Some(QueueError::NotFound));
    }
