    unordered_set<string> bookedSeats;
    mutex bookingMutex;
    const int MAX_CAPACITY = 10000;

public:
    void bookSeat(const string& seatId) {
        lock_guard<mutex> lock(bookingMutex);
        if (bookedSeats.size() >= MAX_CAPACITY) {
            throw runtime_error("Cannot book seat: maximum capacity reached.");
        }
        if (bookedSeats.find(seatId) != bookedSeats.end()) {
            throw runtime_error("Seat " + seatId + " already booked.");
        }
        bookedSeats.insert(seatId);
    }

    void cancelSeat(const string& seatId) {
        lock_guard<mutex> lock(bookingMutex);
        if (bookedSeats.find(seatId) == bookedSeats.end()) {
            throw runtime_error("Seat " + seatId + " not found for cancellation.");
        }
        bookedSeats.erase(seatId);
    }

    bool isSeatAvailable(const string& seatId) {
        lock_guard<mutex> lock(bookingMutex);
        return bookedSeats.find(seatId) == bookedSeats.end();
    }
};

int main() {
    CinemaBookingSystem cinema;

    vector<thread> threads;

    for (int i = 0; i < 5; ++i) {
        threads.emplace_back([&cinema, i]() {
            string seat = "A" + to_string(i);
            try {
                cinema.bookSeat(seat);
