import heapq

class TaskManager:
    def __init__(self):
        self.heap = []
        self.tasks = {}

    def add_task(self, task_id, deadline, details):
        if task_id in self.tasks:
            self.tasks[task_id] = (deadline, details)
            heapq.heappush(self.heap, (deadline, task_id, details))
            return
        if len(self.tasks) < 50:
            self.tasks[task_id] = (deadline, details)
            heapq.heappush(self.heap, (deadline, task_id, details))
        else:
            max_deadline_task = max(self.tasks.items(), key=lambda x: x[1][0], default=None)
            if max_deadline_task and deadline < max_deadline_task[1][0]:
                del self.tasks[max_deadline_task[0]]
                self.tasks[task_id] = (deadline, details)
                heapq.heappush(self.heap, (deadline, task_id, details))

    def update_task(self, task_id, new_deadline, new_details):
        if task_id in self.tasks:
            self.add_task(task_id, new_deadline, new_details)

    def delete_task(self, task_id):
        if task_id in self.tasks:
            del self.tasks[task_id]

    def get_next_task(self):
        while self.heap:
            deadline, task_id, details = heapq.heappop(self.heap)
            if task_id in self.tasks:
                current_deadline, current_details = self.tasks[task_id]
                if current_deadline == deadline:
                    return (task_id, details)
        return None
