import java.util.TreeSet;
import java.util.logging.Level;
import java.util.logging.Logger;

class Task implements Comparable<Task> {
    private String id;
    private int priority;

    public Task(String id, int priority) {
        this.id = id;
        this.priority = priority;
    }

    public String getId() {
        return id;
    }

    public int getPriority() {
        return priority;
    }

    @Override
    public int compareTo(Task other) {
        int priorityCompare = Integer.compare(this.priority, other.priority);
        return priorityCompare != 0 ? priorityCompare : this.id.compareTo(other.id);
    }
}

class TaskScheduler {
    private static final int MAX_CAPACITY = 200;
    private TreeSet<Task> tasks = new TreeSet<>();
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());

    public void addTask(Task task) throws TaskSchedulerFullException, DuplicateTaskException {
        if (tasks.size() >= MAX_CAPACITY) {
            logger.log(Level.SEVERE, "Attempted to add task {0} but scheduler is full.", task.getId());
            throw new TaskSchedulerFullException("Task scheduler is full.");
        }
        for (Task t : tasks) {
            if (t.getId().equals(task.getId())) {
                logger.log(Level.SEVERE, "Duplicate task ID: {0}", task.getId());
                throw new DuplicateTaskException("Task ID already exists: " + task.getId());
            }
        }
        tasks.add(task);
        logger.log(Level.INFO, "Added task: ID={0}, Priority={1}", new Object[]{task.getId(), task.getPriority()});
    }

    public void removeTask(String taskId) throws TaskNotFoundException {
        for (Task task : tasks) {
            if (task.getId().equals(taskId)) {
                tasks.remove(task);
                logger.log(Level.INFO, "Removed task: ID={0}", taskId);
                return;
            }
        }
        logger.log(Level.SEVERE, "Task ID {0} not found for removal.", taskId);
        throw new TaskNotFoundException("Task not found: " + taskId);
    }

    public Task fetchNextTask() throws EmptyTaskSchedulerException {
        if (tasks.isEmpty()) {
            logger.log(Level.SEVERE, "Attempted to fetch from empty scheduler.");
            throw new EmptyTaskSchedulerException("No tasks available.");
        }
        Task task = tasks.pollFirst();
        logger.log(Level.INFO, "Fetched task: ID={0}, Priority={1}", new Object[]{task.getId(), task.getPriority()});
        return task;
    }
}

class TaskSchedulerFullException extends Exception {
    public TaskSchedulerFullException(String message) {
        super(message);
    }
}

class DuplicateTaskException extends Exception {
    public DuplicateTaskException(String message) {
        super(message);
    }
}

class EmptyTaskSchedulerException extends Exception {
    public EmptyTaskSchedulerException(String message) {
        super(message);
    }
}

class TaskNotFoundException extends Exception {
    public TaskNotFoundException(String message) {
        super(message);
    }
}
