struct Item {
    string name;
    int quantity;
    int urgency;

    Item(string n, int q, int u) : name(n), quantity(q), urgency(u) {}
};

struct Compare {
    bool operator()(const Item& a, const Item& b) {
        return a.urgency > b.urgency;
    }
};

int main() {
    priority_queue<Item, vector<Item>, Compare> inventory;

    while (true) {
        cout << "\n1. Add Item\n2. Remove Item\n3. Retrieve Top Item\n4. Exit\nChoice: ";
        int choice;
        cin >> choice;

        if (choice == 4) break;

        switch(choice) {
            case 1: {
                if (inventory.size() >= 500) {
                    cout << "Error: Inventory full (max 500 items).\n";
                    break;
                }
                string name;
                int q, u;
                cout << "Enter name, quantity, urgency: ";
                cin >> name >> q >> u;
                inventory.push(Item(name, q, u));
                cout << "Item added.\n";
                break;
            }
            case 2: {
                if (inventory.empty()) {
                    cout << "Error: Inventory is empty.\n";
                } else {
                    inventory.pop();
                    cout << "Top item removed.\n";
                }
                break;
            }
            case 3: {
                if (inventory.empty()) {
                    cout << "Error: Inventory is empty.\n";
                } else {
                    Item top = inventory.top();
                    cout << "Top Item: " << top.name << ", Quantity: " << top.quantity << ", Urgency: " << top.urgency << endl;
                }
                break;
            }
            default:
                cout << "Invalid choice.\n";
                break;
        }
        cin.clear();
        cin.ignore(numeric_limits<streamsize>::max(), '\n');
    }

    return 0;
}
