            Error::LibraryFull => write!(f, "Media library is full"),
        }
    }
}

enum MediaType {
    Book { title: String, author: String, pages: u32 },
    Movie { title: String, director: String, duration: u32 },
    Music { title: String, artist: String, album: String, duration: u32 },
}

struct MediaEntry {
    id: u32,
    media_type: MediaType,
}

struct MediaLibrary {
    entries: Vec<MediaEntry>,
}

impl MediaLibrary {
    fn new() -> Self {
        MediaLibrary { entries: Vec::with_capacity(1000) }
    }

    fn add_media(&mut self, media_type: MediaType) -> Result<(), Error> {
        if self.entries.len() >= 1000 {
            return Err(Error::LibraryFull);
        }
        let id = self.entries.len() as u32 + 1;
        self.entries.push(MediaEntry { id, media_type });
        Ok(())
    }

    fn update_media(&mut self, id: u32, new_data: MediaType) -> Option<()> {
        if let Some(entry) = self.entries.iter_mut().find(|e| e.id == id) {
            entry.media_type = new_data;
            Some(())
        } else {
            None
        }
    }

    fn find_media(&self, id: u32) -> Option<&MediaType> {
        self.entries.iter().find(|e| e.id == id).map(|e| &e.media_type)
    }
}

fn parse_media_input(
    kind: &str,
    title: String,
    author: String,
    extra: Vec<String>,
) -> Result<MediaType, Error> {
    match kind {
        "book" if extra.len() == 1 => {
            let pages = extra[0].parse().map_err(|_| Error::InvalidMediaType)?;
            Ok(MediaType::Book { title, author, pages })
        }
        "movie" if extra.len() == 1 => {
            let duration = extra[0].parse().map_err(|_| Error::InvalidMediaType)?;
            Ok(MediaType::Movie { title, director: author, duration })
        }
        "music" if extra.len() == 2 => {
            Ok(MediaType::Music { title, artist: author, album: extra[0].clone(), duration: extra[1].parse().map_err(|_| Error::InvalidMediaType)? })
        }
        _ => Err(Error::InvalidMediaType),
    }
}
