public class StudentManager {
    private HashSet<Student> students = new HashSet<>();

    public void addStudent(Student student) {
        if (students.size() >= 500)
            throw new IllegalStateException("Maximum student capacity reached.");
        if (!students.add(student))
            throw new IllegalArgumentException("Student with ID " + student.getStudentId() + " already exists.");
    }

    public void removeStudent(String studentId) {
        Student dummy = new Student(studentId, "", "");
        if (!students.remove(dummy))
            throw new NoSuchElementException("Student with ID " + studentId + " not found.");
    }

    public boolean checkForStudent(String studentId) {
        return students.contains(new Student(studentId, "", ""));
    }
