use smallvec::SmallVec;

#[derive(Debug)]
struct Task {
    id: u32,
    priority: u32,
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        Self {
            tasks: SmallVec::new(),
        }
    }

    fn add_task(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() >= 200 {
            return Err("Queue full");
        }
        let pos = self.tasks.iter().position(|t| t.priority < task.priority).unwrap_or(self.tasks.len());
        self.tasks.insert(pos, task);
        Ok(())
    }

    fn update_priority(&mut self, task_id: u32, new_priority: u32) -> Result<(), &'static str> {
        let pos = self.tasks.iter().position(|t| t.id == task_id).ok_or("Task not found")?;
        let mut task = self.tasks.remove(pos);
        task.priority = new_priority;
        let new_pos = self.tasks.iter().position(|t| t.priority < new_priority).unwrap_or(self.tasks.len());
        self.tasks.insert(new_pos, task);
        Ok(())
    }

    fn remove_task(&mut self, task_id: u32) -> Result<(), &'static str> {
        let pos = self.tasks.iter().position(|t| t.id == task_id).ok_or("Task not found")?;
        self.tasks.remove(pos);
        Ok(())
    }
}
