func main() {
	files := os.Args[1:]
	linesCh := make(chan string)
	aggregatorCh := make(chan string)

	var readersWG sync.WaitGroup
	for _, file := range files {
		readersWG.Add(1)
		go func(f string) {
			defer readersWG.Done()
			file, err := os.Open(f)
			if err != nil {
				return
			}
			defer file.Close()
			scanner := bufio.NewScanner(file)
			for scanner.Scan() {
				linesCh <- scanner.Text()
			}
		}(file)
	}

	go func() {
		readersWG.Wait()
		close(linesCh)
	}()

	var workersWG sync.WaitGroup
	workers := runtime.NumCPU()
	for i := 0; i < workers; i++ {
		workersWG.Add(1)
		go func() {
			defer workersWG.Done()
			for line := range linesCh {
				aggregatorCh <- line
			}
		}()
	}

	go func() {
		workersWG.Wait()
		close(aggregatorCh)
	}()

	var aggregatorWG sync.WaitGroup
	aggregatorWG.Add(1)
	go func() {
		defer aggregatorWG.Done()
		counts := make(map[string]int)
		for key := range aggregatorCh {
			if _, exists := counts[key]; exists {
				counts[key]++
			} else if len(counts) < 20000 {
				counts[key] = 1
			}
		}
	}()
	aggregatorWG.Wait()
