import queue

def floyd_warshall(graph, num_nodes):
    INF = float('inf')
    dist = [[INF] * num_nodes for _ in range(num_nodes)]
    for i in range(num_nodes):
        dist[i][i] = 0
    for u, v, w in graph:
        if dist[u][v] > w:
            dist[u][v] = w

    q = queue.Queue(maxsize=1000)

    for k in range(num_nodes):
        for i in range(num_nodes):
            for j in range(num_nodes):
                while q.full():
                    x, y = q.get()
                    if dist[x][y] > dist[x][k] + dist[k][y]:
                        dist[x][y] = dist[x][k] + dist[k][y]
                q.put((i, j))
        while not q.empty():
            x, y = q.get()
            if dist[x][y] > dist[x][k] + dist[k][y]:
                dist[x][y] = dist[x][k] + dist[k][y]

    return dist
