use arrayvec::ArrayVec;
use log::{error, info, warn};
use std::collections::HashMap;

type EmployeeData = (u32, f64);

fn process_data(entries: &[(u32, f64)]) -> Result<(), arrayvec::CapacityError<EmployeeData>> {
    let mut storage = ArrayVec::<_, 100>::new();
    for &entry in entries {
        storage.try_push(entry)?;
    }
    Ok(())
}

fn calculate_averages(entries: &[(u32, f64)]) -> HashMap<u32, f64> {
    let mut scores = HashMap::new();
    for &(id, score) in entries {
        let entry = scores.entry(id).or_insert((0.0, 0));
        entry.0 += score;
        entry.1 += 1;
    }
    scores
        .into_iter()
        .map(|(id, (total, count))| (id, total / count as f64))
        .collect()
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();
    info!("Processing started");

    let input = vec![(1, 80.0), (2, 90.0), (1, 85.0), (3, 70.0)];

    if let Err(e) = process_data(&input) {
        error!("Data storage overflow: {}", e);
        return Err(e.into());
    }

    if input.is_empty() {
        warn!("No data entries provided");
        return Ok(());
    }

    let averages = calculate_averages(&input);
    for (id, avg) in &averages {
        info!("Employee {} average: {:.2}", id, avg);
    }

    Ok(())
