#include <vector>
#include <unordered_map>
using namespace std;

int longestConsecutive(vector<int>& nums) {
    unordered_map<int, int> map;
    int max_len = 0;
    for (int num : nums) {
        if (map.find(num) != map.end()) continue;
        int left = map.find(num - 1) != map.end() ? map[num - 1] : 0;
        int right = map.find(num + 1) != map.end() ? map[num + 1] : 0;
        int current = left + right + 1;
        map[num] = current;
        max_len = max(max_len, current);
        if (left > 0) map[num - left] = current;
        if (right > 0) map[num + right] = current;
    }
    return max_len;
}
