use std::collections::BTreeMap;
use std::io::{self, BufRead};

struct MedianFinder {
    map: BTreeMap<i32, usize>,
    total_count: usize,
}

impl MedianFinder {
    fn new() -> Self {
        Self {
            map: BTreeMap::new(),
            total_count: 0,
        }
    }

    fn add(&mut self, num: i32) {
        *self.map.entry(num).or_insert(0) += 1;
        self.total_count += 1;
    }

    fn compute_median(&self) -> Option<f64> {
        if self.total_count == 0 {
            return None;
        }
        let mid = self.total_count / 2;
        let targets = if self.total_count % 2 == 1 {
            vec![mid]
        } else {
            vec![mid - 1, mid]
        };
        let mut current = 0;
        let mut found = Vec::new();
        'outer: for (&key, &count) in self.map.iter() {
            let start = current;
            current += count;
            for &target in &targets {
                if start <= target && target < current {
                    found.push(key);
                    if found.len() == targets.len() {
                        break 'outer;
                    }
                }
            }
        }
        Some(found.iter().map(|&x| x as f64).sum::<f64>() / found.len() as f64)
    }
}

fn main() {
    let mut finder = MedianFinder::new();
    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        let line = line.expect("Failed to read line");
        let parts: Vec<&str> = line.split_whitespace().collect();
        match parts.as_slice() {
            ["add", num] => {
                let num = num.parse().expect("Invalid number");
                finder.add(num);
            }
            ["median"] => {
                if let Some(median) = finder.compute_median() {
                    println!("{:.1}", median);
                } else {
                    println!("No elements");
                }
            }
            _ => println!("Unknown command"),
        }
    }
}
