		priceChan <- rand.Float64() * 100
		time.Sleep(time.Millisecond * 10)
	}
}

func processPrices(priceChan <-chan float64) {
	var batch []float64
	for price := range priceChan {
		batch = append(batch, price)
		if len(batch) == 1000 {
			go computeAverage(batch)
			batch = nil
		}
	}
}

func computeAverage(batch []float64) {
	sum := 0.0
	for _, p := range batch {
		sum += p
	}
	fmt.Printf("Rolling average: %.2f\n", sum/float64(len(batch)))
}
