type Book struct {
	Title     string
	Author    string
	Year      int
	IsIssued  bool
}

type Library struct {
	books map[string]*Book
}

func NewLibrary() *Library {
	return &Library{
		books: make(map[string]*Book, 800),
	}
}

func (l *Library) AddBook(title, author string, year int) error {
	if _, exists := l.books[title]; exists {
		return fmt.Errorf("book already exists")
	}
	l.books[title] = &Book{Title: title, Author: author, Year: year, IsIssued: false}
	return nil
}

func (l *Library) RemoveBook(title string) error {
	if _, exists := l.books[title]; !exists {
		return fmt.Errorf("book not found")
	}
	delete(l.books, title)
	return nil
}

func (l *Library) SearchByTitle(title string) *Book {
	return l.books[title]
}

func (l *Library) UpdateIssuedStatus(title string, status bool) error {
	book, exists := l.books[title]
	if !exists {
		return fmt.Errorf("book not found")
	}
	book.IsIssued = status
	return nil
}

func main() {
	library := NewLibrary()
	for {
		fmt.Println("\n1. Add Book\n2. Remove Book\n3. Search Book\n4. Update Issued Status\n5. Exit")
		fmt.Print("Choose option: ")
		var choiceStr string
		fmt.Scanln(&choiceStr)
		choice, err := strconv.Atoi(choiceStr)
		if err != nil {
			fmt.Println("Invalid input")
			continue
		}

