import heapq

class KthSmallest:
    def __init__(self, k):
        self.k = k
        self.heap = []

    def add(self, num):
        if len(self.heap) < self.k:
            heapq.heappush(self.heap, num)
        else:
            if num > self.heap[0]:
                heapq.heappushpop(self.heap, num)
        return self.get_kth_smallest()

    def get_kth_smallest(self):
        return self.heap[0] if len(self.heap) >= self.k else None
