#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

void generate(vector<int>& nums, vector<bool>& used, vector<int>& current, vector<vector<int>>& result, bool& stop) {
    if (stop) return;
    if (current.size() == nums.size()) {
        result.push_back(current);
        if (result.size() >= 1500) stop = true;
        return;
    }
    for (int i = 0; i < nums.size(); ++i) {
        if (used[i] || (i > 0 && nums[i] == nums[i-1] && !used[i-1])) continue;
        used[i] = true;
        current.push_back(nums[i]);
        generate(nums, used, current, result, stop);
        if (stop) return;
        current.pop_back();
        used[i] = false;
    }
}

vector<vector<int>> uniquePermutations(vector<int>& nums) {
    sort(nums.begin(), nums.end());
    vector<vector<int>> result;
    vector<bool> used(nums.size(), false);
    vector<int> current;
    bool stop = false;
    generate(nums, used, current, result, stop);
    return result;
}

int main() {
    vector<int> nums;
    int num;
    while (cin >> num) nums.push_back(num);
    auto permutations = uniquePermutations(nums);
    for (const auto& p : permutations) {
        for (int n : p) cout << n << " ";
        cout << "\n";
    }
    return 0;
}
